// ─────────────────────────────────────────────
// VHSYS :: sales_nf_report
// Rota   : POST /sales_nf_report
// Fase 5 : Fluxos NF
// ─────────────────────────────────────────────
// Input  : { data: { source: { itens: [...] } } }
// Output : { message: 'Sales NF report processed successfully', invoices_updated: number } HTTP 201
// Banco  : UPSERT sales_nf por chave natural (numero + serie + data_emissao)
// Chave  : numero_nf + serie_nf + data_emissao + cnpj_cliente
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.data) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required field: data' }
  };
}

if (!body.data.source || !body.data.source.itens) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required structure: data.source.itens' }
  };
}

if (!Array.isArray(body.data.source.itens)) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'itens must be an array' }
  };
}

const itens = body.data.source.itens;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'input_validated',
  itens_count: itens.length,
  level: 'info'
}));

return { _valid: true, itens };

// Decode HTML entities + Transform NF data
const ctx = $input.first().json;
const itens = ctx.itens;

// Decode HTML entities recursivamente
function decodeHtml(obj) {
  if (typeof obj === 'string') {
    return obj
      .replace(/&amp;/g,  '&')
      .replace(/&lt;/g,   '<')
      .replace(/&gt;/g,   '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g,  "'")
      .replace(/&#x27;/g, "'")
      .replace(/&#x2F;/g, '/')
      .replace(/&nbsp;/g, ' ');
  }
  if (Array.isArray(obj)) return obj.map(decodeHtml);
  if (typeof obj === 'object' && obj !== null) {
    const out = {};
    for (const k in obj) out[k] = decodeHtml(obj[k]);
    return out;
  }
  return obj;
}

// Helper para converter data
function parseDate(dateStr) {
  if (!dateStr) return null;
  // Remove barras e hífens, tenta vários formatos
  const cleaned = String(dateStr).replace(/[^0-9]/g, '');
  if (cleaned.length === 8) {
    // DDMMYYYY ou YYYYMMDD
    const year1 = cleaned.substring(0, 4);
    const year2 = cleaned.substring(4, 8);
    if (year1.startsWith('20') || year1.startsWith('19')) {
      // YYYYMMDD
      return `${year1}-${cleaned.substring(4, 6)}-${cleaned.substring(6, 8)}`;
    } else {
      // DDMMYYYY  
      return `${year2}-${cleaned.substring(2, 4)}-${cleaned.substring(0, 2)}`;
    }
  }
  return dateStr;
}

// Helper para converter valor
function parseValue(value) {
  if (!value) return 0;
  const cleaned = String(value).replace(/[^0-9.,]/g, '').replace(',', '.');
  const num = parseFloat(cleaned);
  return isNaN(num) ? 0 : num;
}

// Helper para gerar chave única
function generateKey(item) {
  const numero = String(item.NumeroNF || item.Numero || '').trim();
  const serie = String(item.SerieNF || item.Serie || '').trim();
  const dataEmissao = parseDate(item.DataEmissao || item.Data || '');
  const cnpjCliente = String(item.CnpjCliente || item.CNPJ || '').replace(/\D/g, '');

  return `${numero}-${serie}-${dataEmissao}-${cnpjCliente}`;
}

const decodedItens = decodeHtml(itens);

const transformedNFs = decodedItens.map((item, index) => {
  const key = generateKey(item);

  if (!key || key === '---') {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      route: 'sales_nf_report',
      event: 'nf_skipped_invalid_key',
      item_index: index,
      item_data: item,
      level: 'warn'
    }));
    return null;
  }

  return {
    chave_nf: key,
    numero_nf: String(item.NumeroNF || item.Numero || '').trim(),
    serie_nf: String(item.SerieNF || item.Serie || '').trim(),
    data_emissao: parseDate(item.DataEmissao || item.Data || ''),
    cnpj_cliente: String(item.CnpjCliente || item.CNPJ || '').replace(/\D/g, ''),
    razao_social_cliente: String(item.RazaoSocial || item.Cliente || '').trim(),
    valor_total: parseValue(item.ValorTotal || item.Valor || 0),
    valor_produtos: parseValue(item.ValorProdutos || 0),
    valor_servicos: parseValue(item.ValorServicos || 0),
    icms: parseValue(item.ICMS || 0),
    ipi: parseValue(item.IPI || 0),
    pis: parseValue(item.PIS || 0),
    cofins: parseValue(item.COFINS || 0),
    situacao: String(item.Situacao || item.Status || 'Normal').trim(),
    observacoes: String(item.Observacoes || item.Obs || '').trim()
  };
}).filter(nf => nf !== null);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'nfs_transformed',
  valid_nfs: transformedNFs.length,
  total_input: decodedItens.length,
  level: 'info'
}));

return transformedNFs;

// Conta registros afetados e constrói resposta
const affectedRecords = $input.all()
  .filter(item => item.json && item.json.chave_nf)
  .length;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'sales_nf_upserted',
  invoices_updated: affectedRecords,
  level: 'info'
}));

// statusCode 201 — preserva compatibilidade com Flask original
return {
  statusCode: 201,
  body: {
    message: 'Sales NF report processed successfully',
    invoices_updated: affectedRecords
  }
};

// Erro de validação
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process sales NF report' }
};

// Return the response data as-is
const response = $input.first().json;
return response;
